class FreqStack {
    Map<Integer, Integer> freqMap;
    Map<Integer, Stack<Integer>> stackMap;

    public FreqStack() {
        freqMap = new HashMap<>();
        stackMap = new HashMap<>();
    }

    public void push(int val) {
        freqMap.put(val, freqMap.getOrDefault(val, 0) + 1);
        stackMap.computeIfAbsent(val, k -> new Stack<>()).push(val);
    }

    public int pop() {
        int maxFreq = 0;
        int res = 0;
        for (Map.Entry<Integer, Stack<Integer>> entry : stackMap.entrySet()) {
            if (entry.getValue().size() > 0 && entry.getKey() > maxFreq) {
                maxFreq = entry.getKey();
                res = entry.getValue().pop();
            }
        }
        freqMap.put(maxFreq, freqMap.get(maxFreq) - 1);
        if (freqMap.get(maxFreq) == 0) {
            stackMap.remove(maxFreq);
        }
        return res;
    }
}

